// ---------------------------------------------------------------------------
// parse_envelope_header error paths — drives ClientErrorCode::Invalid* codes
// through the FFI surface.
// ---------------------------------------------------------------------------

#[test]
fn uniffi_parse_envelope_header_rejects_short_bytes() {
    let result = parse_envelope_header(Vec::new());
    assert_eq!(result.code, ClientErrorCode::InvalidHeaderLength.as_u16());
    assert_eq!(result.epoch_id, 0);
    assert_eq!(result.shard_index, 0);
    assert_eq!(result.tier, 0);
    assert!(result.nonce.is_empty());
}

#[test]
fn uniffi_parse_envelope_header_rejects_bad_magic() {
    // 64 bytes that look like a header but do not start with the magic prefix.
    let bytes = vec![0_u8; 64];
    let result = parse_envelope_header(bytes);
    assert_eq!(result.code, ClientErrorCode::InvalidMagic.as_u16());
    assert!(result.nonce.is_empty());
}

// ---------------------------------------------------------------------------
// Phase string lookup coverage. Each iteration exercises one arm of
// `upload_phase_from_string` / `album_sync_phase_from_string`. We do not
// assert on the resulting `code`: the SM may reject the synthetic snapshot
// for reasons unrelated to the FFI's phase lookup (e.g. ApplyingPage requires
// `current_page` which the DTO cannot carry; UploadingShard requires a
// pending `shard_id`). The coverage we care about — the matching arm
// inside `*_phase_from_string` — has already executed by the time
// `advance_*` returns, so a non-panicking call is enough.
// ---------------------------------------------------------------------------

#[test]
fn uniffi_advance_upload_job_accepts_every_known_phase_string() {
    for phase in [
        "Queued",
        "AwaitingPreparedMedia",
        "AwaitingEpochHandle",
        "EncryptingShard",
        "CreatingShardUpload",
        "UploadingShard",
        "CreatingManifest",
        "ManifestCommitUnknown",
        "AwaitingSyncConfirmation",
        "RetryWaiting",
        "Confirmed",
        "Cancelled",
        "Failed",
    ] {
        let mut snapshot = baseline_upload_snapshot();
        snapshot.phase = phase.to_owned();
        let _ = advance_upload_job(snapshot, upload_event("CancelRequested", 0, 0, 0));
    }
}

#[test]
fn uniffi_advance_album_sync_accepts_every_known_phase_string() {
    for phase in [
        "Idle",
        "FetchingPage",
        "ApplyingPage",
        "RetryWaiting",
        "Completed",
        "Cancelled",
        "Failed",
    ] {
        let mut snapshot = baseline_album_sync_snapshot();
        snapshot.phase = phase.to_owned();
        let _ = advance_album_sync(snapshot, album_sync_event("CancelRequested", 0));
    }
}

