#[test]
fn uniffi_inspect_media_image_returns_invalid_png_on_truncated_signature() {
    let mut bytes = PNG_SIGNATURE.to_vec();
    bytes.extend_from_slice(&[0_u8; 2]);
    let result = inspect_media_image(bytes);
    assert_eq!(result.code, ClientErrorCode::InvalidMediaContainer.as_u16());
    assert_eq!(result.format, "");
}

#[test]
fn uniffi_inspect_media_image_returns_invalid_jpeg_on_truncated_jpeg() {
    let bytes = vec![0xff, 0xd8];
    let result = inspect_media_image(bytes);
    assert_eq!(result.code, ClientErrorCode::InvalidMediaContainer.as_u16());
}

#[test]
fn uniffi_inspect_media_image_returns_invalid_webp_on_truncated_riff() {
    let mut bytes = b"RIFF".to_vec();
    bytes.extend_from_slice(&[0, 0, 0, 0]);
    bytes.extend_from_slice(b"WEBP");
    let result = inspect_media_image(bytes);
    assert_eq!(result.code, ClientErrorCode::InvalidMediaContainer.as_u16());
}

#[test]
fn uniffi_inspect_media_image_recognizes_minimal_jpeg_with_sof0() {
    // SOI + SOF0 segment (precision 8, height 4, width 8, components 1).
    let bytes = vec![
        0xff, 0xd8, 0xff, 0xc0, 0x00, 0x0b, 0x08, 0x00, 0x04, 0x00, 0x08, 0x01, 0x01, 0x11, 0x00,
    ];
    let result = inspect_media_image(bytes);
    assert_eq!(result.code, 0);
    assert_eq!(result.format, "jpeg");
    assert_eq!(result.mime_type, "image/jpeg");
    assert_eq!(result.width, 8);
    assert_eq!(result.height, 4);
}

#[test]
fn uniffi_inspect_media_image_recognizes_minimal_webp_vp8l() {
    let payload = build_webp_vp8l(10, 6);
    let result = inspect_media_image(payload);
    assert_eq!(result.code, 0);
    assert_eq!(result.format, "webp");
    assert_eq!(result.mime_type, "image/webp");
    assert_eq!(result.width, 10);
    assert_eq!(result.height, 6);
}

