#[test]
fn uniffi_canonical_metadata_sidecar_bytes_rejects_invalid_album_uuid() {
    let result =
        canonical_metadata_sidecar_bytes(vec![0x11; 15], [0x22; 16].to_vec(), 4, Vec::new());
    assert_eq!(result.code, ClientErrorCode::InvalidInputLength.as_u16());
    assert!(result.bytes.is_empty());
}

#[test]
fn uniffi_canonical_metadata_sidecar_bytes_rejects_truncated_field_payload() {
    // A field that declares value_len=4 but only supplies 2 bytes triggers
    // the `end > encoded_fields.len()` rejection inside
    // metadata_fields_from_encoded.
    let mut encoded = Vec::new();
    encoded.extend_from_slice(&7_u16.to_le_bytes());
    encoded.extend_from_slice(&4_u32.to_le_bytes());
    encoded.extend_from_slice(&[0xab, 0xcd]);
    let result =
        canonical_metadata_sidecar_bytes([0x11; 16].to_vec(), [0x22; 16].to_vec(), 9, encoded);
    assert_eq!(result.code, ClientErrorCode::InvalidInputLength.as_u16());
    assert!(result.bytes.is_empty());
}

